module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

reg [4:0] state;
reg [4:0] next_state;
reg match_reg;

parameter IDLE = 5'b00001;
parameter S1   = 5'b00010;
parameter S2   = 5'b00100;
parameter S3   = 5'b01000;
parameter S4   = 5'b10000;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= IDLE;
        match_reg <= 1'b0;
    end else begin
        state <= next_state;
        match_reg <= (state == S4) ? 1'b1 : 1'b0;
    end
end

always @(*) begin
    case (state)
        IDLE: begin
            if (IN) begin
                next_state = S1;
            end else begin
                next_state = IDLE;
            end
        end
        S1: begin
            if (IN) begin
                next_state = S1;
            end else begin
                next_state = S2;
            end
        end
        S2: begin
            if (IN) begin
                next_state = S1;
            end else begin
                next_state = S3;
            end
        end
        S3: begin
            if (IN) begin
                next_state = S4;
            end else begin
                next_state = IDLE;
            end
        end
        S4: begin
            if (IN) begin
                next_state = S1;
            end else begin
                next_state = IDLE;
            end
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end

assign MATCH = match_reg;

endmodule
